import re
import operator
import logging
from functools import partial
from pprint import pformat

class _Token:
    def __init__(self, typ, value, pos):
        self.type = typ
        self.value = value
        self.pos = pos

    def __repr__(self):
        return f"_Token({self.type}, {self.value}, {self.pos})"


def _tokenize_where(expr):
    token_spec = [
        ("SKIP", r"[ \t\r\n]+"),
        ("LPAREN", r"\("),
        ("RPAREN", r"\)"),
        ("COMMA", r","),
        ("OP", r"<=|>=|<>|!=|=|<|>"),
        ("STRING", r"'(?:\\.|[^'])*'"),
        ("NUMBER", r"\d+(?:\.\d+)?"),
        ("NAME", r"[A-Za-z_][A-Za-z0-9_\.]*"),
    ]
    tok_regex = "|".join(f"(?P<{name}>{pattern})" for name, pattern in token_spec)
    keywords = {"AND", "OR", "NOT", "IS", "NULL", "IN", "LIKE", "TRUE", "FALSE"}
    tokens = []
    for m in re.finditer(tok_regex, expr):
        kind = m.lastgroup
        value = m.group()
        pos = m.start()
        if kind == "SKIP":
            continue
        if kind == "NAME":
            upper_val = value.upper()
            if upper_val in keywords:
                kind = upper_val
                value = upper_val
        tokens.append(_Token(kind, value, pos))
    return tokens


def _unescape_sql_string(s):
    # Strip surrounding single quotes and unescape common sequences
    assert s[0] == "'" and s[-1] == "'"
    inner = s[1:-1]
    # Replace escaped sequences
    inner = inner.replace(r"\'", "'").replace(r"\\", "\\")
    inner = inner.replace(r"\n", "\n").replace(r"\t", "\t").replace(r"\r", "\r")
    return inner


def _to_number(value_str):
    if "." in value_str:
        try:
            return float(value_str)
        except ValueError:
            return value_str
    try:
        return int(value_str)
    except ValueError:
        return value_str


def _get_field_value(record, field):
    # Support dotted paths for nested dicts
    parts = field.split(".")
    cur = record
    for p in parts:
        if not isinstance(cur, dict):
            return None
        if p in cur:
            cur = cur[p]
        else:
            return None
    return cur


def _coerce_for_compare(lhs, rhs):
    # Try to coerce rhs to type of lhs for meaningful comparison
    if lhs is None:
        return None, None
    if isinstance(lhs, bool):
        # Consider 'true'/'false' strings or 1/0 numbers
        if isinstance(rhs, str):
            low = rhs.strip().lower()
            if low in ("true", "1"):
                return lhs, True
            if low in ("false", "0"):
                return lhs, False
        if isinstance(rhs, (int, float)):
            return lhs, bool(rhs)
    if isinstance(lhs, (int, float)):
        if isinstance(rhs, (int, float)):
            return lhs, rhs
        if isinstance(rhs, str):
            try:
                if "." in rhs:
                    return lhs, float(rhs)
                return lhs, int(rhs)
            except ValueError:
                return lhs, rhs
    if isinstance(lhs, str):
        if rhs is None:
            return lhs, None
        return lhs, str(rhs)
    return lhs, rhs


def _like_to_regex(pattern):
    # Convert SQL LIKE pattern to Python regex pattern
    # % -> .*, _ -> .
    # Escape regex metacharacters except SQL wildcards
    regex = ""
    i = 0
    while i < len(pattern):
        c = pattern[i]
        if c == "%":
            regex += ".*"
        elif c == "_":
            regex += "."
        else:
            regex += re.escape(c)
        i += 1
    return f"^{regex}$"


class _WhereParser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def _peek(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def _consume(self, expected_type=None):
        tok = self._peek()
        if tok is None:
            raise ValueError("Unexpected end of WHERE clause")
        if expected_type and tok.type != expected_type:
            raise ValueError(f"Expected {expected_type} at position {tok.pos}, got {tok.type}")
        self.pos += 1
        return tok

    def parse(self):
        if not self.tokens:
            # No tokens: empty predicate: always True
            return lambda rec: True
        expr = self._parse_expression()
        return expr

    def _parse_expression(self):
        left = self._parse_term()
        while True:
            tok = self._peek()
            if tok and tok.type == "OR":
                self._consume("OR")
                right = self._parse_term()
                left = self._combine_or(left, right)
            else:
                break
        return left

    def _parse_term(self):
        left = self._parse_factor()
        while True:
            tok = self._peek()
            if tok and tok.type == "AND":
                self._consume("AND")
                right = self._parse_factor()
                left = self._combine_and(left, right)
            else:
                break
        return left

    def _parse_factor(self):
        tok = self._peek()
        if tok is None:
            raise ValueError("Unexpected end of WHERE clause")
        if tok.type == "NOT":
            self._consume("NOT")
            inner = self._parse_factor()
            return lambda rec, inner=inner: not inner(rec)
        if tok.type == "LPAREN":
            self._consume("LPAREN")
            inner = self._parse_expression()
            self._consume("RPAREN")
            return inner
        return self._parse_comparison()

    def _parse_comparison(self):
        # identifier first
        left_tok = self._consume()
        if left_tok.type not in ("NAME",):
            raise ValueError(f"Expected identifier at position {left_tok.pos}")
        field = left_tok.value

        tok = self._peek()
        if tok is None:
            raise ValueError("Incomplete comparison in WHERE clause")

        # IS [NOT] NULL
        if tok.type == "IS":
            self._consume("IS")
            not_tok = self._peek()
            is_not = False
            if not_tok and not_tok.type == "NOT":
                self._consume("NOT")
                is_not = True
            null_tok = self._consume()
            if null_tok.type != "NULL":
                raise ValueError(f"Expected NULL at position {null_tok.pos}")
