                return False
            lvc, rvc = _coerce_for_compare(lv, rv)
            try:
                return cmp(lvc, rvc)
            except Exception:
                # Fallback: compare as strings
                try:
                    return cmp(str(lv), str(rv))
                except Exception:
                    return False

        return comparator

    @staticmethod
    def _combine_and(a, b):
